class BudgetedConversation(Conversation):
    def __init__(self, system_prompt: str, model: str = 'gpt-4o-mini', token_budget: int = 10_000):
        super().__init__(system_prompt, model)
        self.token_budget = token_budget
        self.tokens_used = 0
        self.CONTEXT_LIMITS = {'gpt-4o': 128_000, 'gpt-4o-mini': 128_000}

    def _count_tokens(self, messages: list[dict]) -> int:
        return sum(len(str(m.get('content', ''))) // 4 for m in messages)

    def send(self, user_message: str) -> str:
        if self.tokens_used >= self.token_budget:
            raise RuntimeError(f'Session token budget ({self.token_budget}) exhausted.')

        current_tokens = self._count_tokens(self.messages)
        limit = self.CONTEXT_LIMITS.get(self.model, 128_000)
        if current_tokens > limit * 0.5:
            print(f'[WARN] Using {current_tokens/limit:.0%} of context window')

        self.messages.append({'role': 'user', 'content': user_message})
        reply = chat(self.messages, model=self.model)
        self.messages.append({'role': 'assistant', 'content': reply})
        self.tokens_used += self._count_tokens([{'role': 'assistant', 'content': reply}])
        return reply

    def cost_summary(self) -> dict:
        pricing = {'gpt-4o-mini': {'input': 0.15, 'output': 0.60}}.get(self.model, {'input': 2.50, 'output': 10.00})
        cost = (self.tokens_used / 1_000_000) * (pricing['input'] + pricing['output']) / 2
        return {'tokens_used': self.tokens_used, 'estimated_cost_usd': round(cost, 6)}

