import logging
from openai import OpenAI, RateLimitError, APIConnectionError, AuthenticationError, APIStatusError

client = OpenAI()
log = logging.getLogger(__name__)

def safe_chat(messages: list[dict], **kwargs) -> str | None:
    try:
        response = client.chat.completions.create(
            model=kwargs.get('model', 'gpt-4o'),
            messages=messages,
            **{k: v for k, v in kwargs.items() if k != 'model'}
        )
        return response.choices[0].message.content
    except RateLimitError:
        log.warning('Rate limited by OpenAI API')
    except AuthenticationError:
        log.error('Invalid OpenAI API key')
    except APIConnectionError:
        log.warning('Network error connecting to OpenAI')
    except APIStatusError as e:
        log.error('OpenAI API error %s: %s', e.status_code, e.message)
    return None
